import { bisectLeft, bisectRight } from 'bisect';

function solve(nums, queries) {
    const n = nums.length;
    const depthMap = new Array(n).fill(0);
    const depthArray = new Array(n).fill(0);

    // Precompute the popcount-depth for each number in nums
    for (let i = 0; i < n; i++) {
        let x = nums[i];
        let d = 0;
        while (x > 0) {
            x = x & (x - 1); // Clear the least significant bit
            d++;
        }
        depthMap[i] = d;
        depthArray[i] = d;
    }

    // Create a list of depth values for binary search
    const depthList = depthArray.slice();

    // For each query
    const answer = [];
    for (const query of queries) {
        if (query[0] === 1) {
            const [l, r, k] = query.slice(1);
            // Find the number of elements in [l, r] with popcount-depth equal to k
            const left = bisectLeft(depthList, k, l, r + 1);
            const right = bisectRight(depthList, k, l, r + 1);
            answer.push(right - left);
        } else {
            const [idx, val] = query.slice(1);
            // Update the value at idx
            let x = val;
            let d = 0;
            while (x > 0) {
                x = x & (x - 1);
                d++;
            }
            depthMap[idx] = d;
            depthArray[idx] = d;
            depthList[idx] = d;
        }
    }

    return answer;
}

